#include <iostream>
using namespace std;

void printDetails(string name, int age = 18, string country = "Unknown") {
  cout << name << ", " << age << ", from " << country << endl;
}

int main() {
  printDetails("Alice", 25, "USA");
  printDetails("Bob", 22);          // Uses default country
  printDetails("Charlie");          // Uses default age and country
  return 0;
}
